class SecurityError(Exception):
    """Raised when a security violation is detected."""
    pass


class ExpressionValidator:
    """Validates JavaScript expressions for safety before execution."""

    MAX_EXPRESSION_LENGTH = 200

    @staticmethod
    def validate(expression: str) -> bool:
        """
        Validate a JavaScript expression against known dangerous patterns.

        Returns True if the expression appears safe, raises SecurityError otherwise.
        """
        if not expression or not isinstance(expression, str):
            raise SecurityError("Expression must be a non-empty string")

        if len(expression) > ExpressionValidator.MAX_EXPRESSION_LENGTH:
            raise SecurityError(
                f"Expression exceeds maximum length of "
                f"{ExpressionValidator.MAX_EXPRESSION_LENGTH} characters"
            )

        # Check for dangerous patterns
        for pattern in DANGEROUS_PATTERNS:
            if re.search(pattern, expression, re.IGNORECASE):
                logger.warning(
                    "Blocked dangerous expression pattern: %s in expression: %s",
                    pattern, expression
                )
                raise SecurityError(
                    f"Expression contains forbidden pattern: {pattern}"
                )

        # Only allow expressions that reference 'this.' fields with simple comparisons
        # This is a allowlist approach for the expression structure
        allowed_tokens = re.compile(
            r'^[\s\w\.\'\"\+\-\*\/\>\<\=\!\&\|\(\)\,\[\]]+$'
        )
        if not allowed_tokens.match(expression):
            raise SecurityError("Expression contains disallowed characters")

        return True


class SafeQueryBuilder:
    """
    Builds MongoDB queries using native operators instead of $where.
    THIS IS THE RECOMMENDED APPROACH.
    """

    @staticmethod
    def build_comparison_query(field: str, operator: str, value: Any) -> dict:
        """Build a safe comparison query using MongoDB operators."""
        op_map = {
            "eq": "$eq",
            "ne": "$ne",
            "gt": "$gt",
            "gte": "$gte",
            "lt": "$lt",
            "lte": "$lte",
            "in": "$in",
            "nin": "$nin",
            "regex": "$regex",
            "exists": "$exists",
            "type": "$type",
        }

        if operator not in op_map:
            raise ValueError(f"Unknown operator: {operator}")

        # Sanitize field name
        if not re.match(r'^[a-zA-Z_][a-zA-Z0-9_.]*$', field):
            raise SecurityError(f"Invalid field name: {field}")

        return {field: {op_map[operator]: value}}

    @staticmethod
    def build_compound_query(conditions: list, logic: str = "and") -> dict:
        """Build a compound query with AND/OR logic."""
        if logic == "and":
            return {"$and": conditions}
        elif logic == "or":
            return {"$or": conditions}
        else:
            raise ValueError(f"Unknown logic operator: {logic}")

    @staticmethod
    def build_cross_field_comparison(
        field1: str, operator: str, field2: str
    ) -> dict:
        """
        Build a cross-field comparison using $expr (safe alternative to $where).
        """
        op_map = {
            "eq": "$eq",
            "ne": "$ne",
            "gt": "$gt",
            "gte": "$gte",
            "lt": "$lt",
            "lte": "$lte",
        }

        if operator not in op_map:
            raise ValueError(f"Unknown operator: {operator}")

        for f in [field1, field2]:
            if not re.match(r'^[a-zA-Z_][a-zA-Z0-9_.]*$', f):
                raise SecurityError(f"Invalid field name: {f}")

        return {"$expr": {op_map[operator]: [f"${field1}", f"${field2}"]}}


class MongoFilterService:
    """
    Advanced data filtering service for MongoDB.

    Supports both safe native query operators and (with caution) $where expressions.
    """

    def __init__(
        self,
        connection_string: str = "mongodb://localhost:27017",
        database: str = "filter_service",
        collection: str = "documents",
    ):
        self.client = MongoClient(
            connection_string,
            serverSelectionTimeoutMS=5000,
            socketTimeoutMS=10000,
        )
        self.db = self.client[database]
        self.collection = self.db[collection]
        self.validator = ExpressionValidator()
        self.safe_builder = SafeQueryBuilder()
        self.audit_collection = self.db["query_audit_log"]

    def _audit_log(self, query_type: str, query: Any, user: str, success: bool):
        """Log all queries for security auditing."""
        try:
            self.audit_collection.insert_one({
                "timestamp": datetime.utcnow(),
                "query_type": query_type,
                "query": str(query),
                "user": user,
                "success": success,
            })
        except PyMongoError:
            logger.error("Failed to write audit log")

    def execute_predefined_filter(
        self, filter_name: str, user: str = "anonymous"
    ) -> list:
        """
        Execute a predefined (allowlisted) $where expression.

        This is the ONLY safe way to use $where — with expressions that are
        NOT derived from user input.
        """
        if filter_name not in ALLOWED_EXPRESSIONS:
            self._audit_log("predefined_where", filter_name, user, False)
            raise ValueError(
                f"Unknown filter: {filter_name}. "
                f"Available filters: {list(ALLOWED_EXPRESSIONS.keys())}"
            )

        expression = ALLOWED_EXPRESSIONS[filter_name]
        logger.info("Executing predefined filter: %s", filter_name)

        try:
            # $where with a predefined, audited expression
            results = list(self.collection.find({"$where": expression}))
            self._audit_log("predefined_where", filter_name, user, True)
            return results
        except OperationFailure as e:
            self._audit_log("predefined_where", filter_name, user, False)
            logger.error("MongoDB operation failed: %s", e)
            raise

    def execute_safe_filter(
        self,
        conditions: list[dict],
        logic: str = "and",
        user: str = "anonymous",
    ) -> list:
        """
        Execute a safe filter using MongoDB's native query operators.

        THIS IS THE RECOMMENDED METHOD.

        Each condition is a dict with keys: field, operator, value
        Example:
            conditions = [
                {"field": "age", "operator": "gt", "value": 25},
                {"field": "status", "operator": "eq", "value": "active"},
            ]
        """
        query_parts = []

        for condition in conditions:
            field = condition.get("field")
            operator = condition.get("operator")
            value = condition.get("value")

            if not all([field, operator]):
                raise ValueError(f"Invalid condition: {condition}")

            query_part = self.safe_builder.build_comparison_query(
                field, operator, value
            )
            query_parts.append(query_part)

        if len(query_parts) == 1:
            query = query_parts[0]
        else:
            query = self.safe_builder.build_compound_query(query_parts, logic)

        logger.info("Executing safe filter: %s", query)

        try:
            results = list(self.collection.find(query))
            self._audit_log("safe_filter", query, user, True)
            return results
        except PyMongoError as e:
            self._audit_log("safe_filter", query, user, False)
            logger.error("Query failed: %s", e)
            raise

    def execute_cross_field_filter(
        self,
        field1: str,
        operator: str,
        field2: str,
        user: str = "anonymous",
    ) -> list:
        """
        Compare two fields using $expr (safe alternative to $where for cross-field).

        Example: Find documents where 'score' > 'threshold'
        """
        query = self.safe_builder.build_cross_field_comparison(
            field1, operator, field2
        )
        logger.info("Executing cross-field filter: %s", query)

        try:
            results = list(self.collection.find(query))
            self._audit_log("cross_field_filter", query, user, True)
            return results
        except PyMongoError as e:
            self._audit_log("cross_field_filter", query, user, False)
            logger.error("Query failed: %s", e)
            raise

    def execute_aggregation_filter(
        self,
        match_conditions: list[dict],
        computed_fields: Optional[dict] = None,
        user: str = "anonymous",
    ) -> list:
        """
        Execute complex filters using the aggregation pipeline.

        This is a powerful and SAFE alternative to $where for complex logic.
        """
        pipeline = []

        # Add computed fields if needed
        if computed_fields:
            add_fields = {}
            for name, expr in computed_fields.items():
                if not re.match(r'^[a-zA-Z_][a-zA-Z0-9_]*$', name):
                    raise SecurityError(f"Invalid field name: {name}")
                add_fields[name] = expr
            pipeline.append({"$addFields": add_fields})

        # Build match stage
        match_parts = []
        for condition in match_conditions:
            field = condition.get("field")
            operator = condition.get("operator")
            value = condition.get("value")

            if not all([field, operator]):
                raise ValueError(f"Invalid condition: {condition}")

            match_parts.append(
                self.safe_builder.build_comparison_query(field, operator, value)
            )

        if len(match_parts) == 1:
            pipeline.append({"$match": match_parts[0]})
        else:
            pipeline.append({"$match": {"$and": match_parts}})

        logger.info("Executing aggregation filter pipeline: %s", pipeline)

        try:
            results = list(self.collection.aggregate(pipeline))
            self._audit_log("aggregation_filter", str(pipeline), user, True)
            return results
        except PyMongoError as e:
            self._audit_log("aggregation_filter", str(pipeline), user, False)
            logger.error("Aggregation failed: %s", e)
            raise

    def execute_validated_where(
        self, expression: str, user: str = "anonymous"
    ) -> list:
        """
        Execute a $where expression WITH validation.

        ⚠️ WARNING: Even with validation, this is NOT recommended for
        user-provided input. Use execute_safe_filter() or
        execute_aggregation_filter() instead.

        This method exists to demonstrate defense-in-depth for cases where
        $where is absolutely unavoidable.
        """
        logger.warning(
            "Using $where with expression validation. "
            "Consider using safe alternatives instead. User: %s", user
        )

        try:
            self.validator.validate(expression)
        except SecurityError as e:
            self._audit_log("validated_where_BLOCKED", expression, user, False)
            logger.warning(
                "Blocked potentially dangerous $where expression from user %s: %s",
                user, expression
            )
            raise

        try:
            results = list(self.collection.find({"$where": expression}))
            self._audit_log("validated_where", expression, user, True)
            return results
        except OperationFailure as e:
            self._audit_log("validated_where", expression, user, False)
            logger.error("$where execution failed: %s", e)
            raise

