def demonstrate_safe_queries(service: MongoFilterService):
    """Demonstrate the recommended safe query patterns."""
    print("\n" + "=" * 70)
    print("RECOMMENDED: Safe Query Patterns (No $where)")
    print("=" * 70)

    # 1. Simple comparison filter
    print("\n--- 1. Simple Filter: age > 30 ---")
    results = service.execute_safe_filter(
        conditions=[{"field": "age", "operator": "gt", "value": 30}],
        user="demo_user",
    )
    for doc in results:
        print(f"  {doc.get('name')}, age: {doc.get('age')}")

    # 2. Compound filter
    print("\n--- 2. Compound Filter: active=True AND department='engineering' ---")
    results = service.execute_safe_filter(
        conditions=[
            {"field": "active", "operator": "eq", "value": True},
            {"field": "department", "operator": "eq", "value": "engineering"},
        ],
        logic="and",
        user="demo_user",
    )
    for doc in results:
        print(f"  {doc.get('name')}, dept: {doc.get('department')}, active: {doc.get('active')}")

    # 3. Cross-field comparison using $expr
    print("\n--- 3. Cross-Field: score > threshold (using $expr, safe!) ---")
    results = service.execute_cross_field_filter(
        field1="score",
        operator="gt",
        field2="threshold",
        user="demo_user",
    )
    for doc in results:
        print(
            f"  {doc.get('name')}, score: {doc.get('score')}, "
            f"threshold: {doc.get('threshold')}"
        )

    # 4. Aggregation pipeline filter
    print("\n--- 4. Aggregation: Compute score_ratio, filter by it ---")
    results = service.execute_aggregation_filter(
        match_conditions=[
            {"field": "active", "operator": "eq", "value": True},
        ],
        computed_fields={
            "score_ratio": {"$divide": ["$score", "$threshold"]},
        },
        user="demo_user",
    )
    for doc in results:
        print(
            f"  {doc.get('name')}, score_ratio: {doc.get('score_ratio', 'N/A'):.2f}"
        )


