def demonstrate_security_blocking(service: MongoFilterService):
    """Demonstrate that malicious expressions are blocked."""
    print("\n" + "=" * 70)
    print("SECURITY: Demonstrating Injection Blocking")
    print("=" * 70)

    malicious_expressions = [
        # Attempt to access other collections
        "db.users.find()",
        # Attempt to drop collection
        "db.collection.drop()",
        # Attempt denial of service
        "sleep(10000)",
        # Attempt to use loops (DoS)
        "while(true) {}",
        # Attempt to execute functions
        "function() { return true; }",
        # Attempt prototype pollution
        "this.__proto__.isAdmin = true",
        # Attempt to use eval
        "eval('db.dropDatabase()')",
        # Extremely long expression (DoS)
        "this.a" + " && this.a" * 100,
    ]

    for expr in malicious_expressions:
        display = expr[:60] + "..." if len(expr) > 60 else expr
        try:
            service.execute_validated_where(expr, user="attacker")
            print(f"  ❌ FAILED TO BLOCK: {display}")
        except SecurityError as e:
            print(f"  ✅ BLOCKED: {display}")
            print(f"     Reason: {e}")
        except Exception as e:
            print(f"  ⚠️  Error: {display} -> {e}")


def interactive_demo(service: MongoFilterService):
    """Interactive demo showing safe query building."""
    print("\n" + "=" * 70)
    print("INTERACTIVE: Build Safe Queries")
    print("=" * 70)

    while True:
        print("\nOptions:")
        print("  1. Simple field comparison")
        print("  2. Cross-field comparison (using $expr)")
        print("  3. Use predefined $where filter")
        print("  4. Quit")

        choice = input("\nSelect option (1-4): ").strip()

        if choice == "1":
            field = input("Field name: ").strip()
            print("Operators: eq, ne, gt, gte, lt, lte, in, exists, regex")
            operator = input("Operator: ").strip()
            value_str = input("Value: ").strip()

            # Attempt type conversion
            try:
                value: Any = int(value_str)
            except ValueError:
                try:
                    value = float(value_str)
                except ValueError:
                    if value_str.lower() == "true":
                        value = True
                    elif value_str.lower() == "false":
                        value = False
                    else:
                        value = value_str

            try:
                results = service.execute_safe_filter(
                    conditions=[
                        {"field": field, "operator": operator, "value": value}
                    ],
                    user="interactive_user",
                )
                print(f"\nFound {len(results)} documents:")
                for doc in results:
                    doc.pop("_id", None)
                    print(f"  {doc}")
            except (ValueError, SecurityError) as e:
                print(f"Error: {e}")

        elif choice == "2":
            field1 = input("First field: ").strip()
            print("Operators: eq, ne, gt, gte, lt, lte")
            operator = input("Operator: ").strip()
            field2 = input("Second field: ").strip()

            try:
                results = service.execute_cross_field_filter(
                    field1, operator, field2, user="interactive_user"
                )
                print(f"\nFound {len(results)} documents:")
                for doc in results:
                    doc.pop("_id", None)
                    print(f"  {doc}")
            except (ValueError, SecurityError) as e:
                print(f"Error: {e}")

        elif choice == "3":
            print(f"Available filters: {list(ALLOWED_EXPRESSIONS.keys())}")
            name = input("Filter name: ").strip()
            try:
                results = service.execute_predefined_filter(
                    name, user="interactive_user"
                )
                print(f"\nFound {len(results)} documents:")
                for doc in results:
                    doc.pop("_id", None)
                    print(f"  {doc}")
            except ValueError as e:
                print(f"Error: {e}")

        elif choice == "4":
            break
        else:
            print("Invalid option")


def main():
    """Main entry point."""
    print("MongoDB Advanced Data Filtering Service")
    print("=" * 70)
    print()
    print("⚠️  SECURITY NOTICE:")
    print("   This service demonstrates SAFE alternatives to $where.")
    print("   Direct user input should NEVER be passed to $where.")
    print("   Use MongoDB's native operators ($expr, $match, etc.) instead.")
    print()

    service = MongoFilterService(
        connection_string="mongodb://localhost:27017",
        database="filter_service_demo",
        collection="documents",
    )

    try:
        # Test connection
        service.client.admin.command("ping")
        logger.info("Connected to MongoDB successfully")

        # Seed sample data
        service.seed_sample_data()

        # Run demonstrations
        demonstrate_safe_queries(service)
        demonstrate_predefined_where(service)
        demonstrate_security_blocking(service)

        # Interactive mode
        run_interactive = input(
            "\nRun interactive demo? (y/n): "
        ).strip().lower()
        if run_interactive == "y":
            interactive_demo(service)

    except Exception as e:
        logger.error("Service error: %s", e)
        print(f"\nError: {e}")
        print("Make sure MongoDB is running on localhost:27017")
    finally:
        service.close()
        logger.info("Service shut down")


if __name__ == "__main__":
    main()